#!/usr/bin/env bash
# build-sell-a-business-case-to-th.sh — Build & sell a business case to the economic buyer（构建业务价值论证并卖给经济决策人） SOP walkthrough for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
WORKFLOW="Build & sell a business case to the economic buyer（构建业务价值论证并卖给经济决策人）"

usage() {
  cat <<EOF
build-sell-a-business-case-to-th.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./build-sell-a-business-case-to-th.sh             # interactive
  ./build-sell-a-business-case-to-th.sh --dry-run
  ./build-sell-a-business-case-to-th.sh --json
  ./build-sell-a-business-case-to-th.sh --explain
  ./build-sell-a-business-case-to-th.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Build & sell a business case to the economic buyer（构建业务价值论证并卖给经济决策人）" 工作流。

一句话: Convert a quantified problem into a value narrative (before/after + business outcomes + ROI) and deliver it *to the person who controls the budget* — the move from "feature selling to users" to "value selling to the EB." (evidence: [T03-S016, T03-S007])

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Quantify the business value** — translate the discovered pain into a metric the buyer owns (cost today vs. future state; the \"M\" in MEDDIC). (evidence: [T03-S007])"
  "**Build the value narrative (Command of the Message)** — Before/After states, negative consequences of inaction, PBOs, required capabilities, and your differentiation vs. alternatives (including status quo). (evidence: [T03-S016])"
  "**Get access to the Economic Buyer** — use the champion to identify and introduce the EB; if the champion can't/won't, that's a red flag. (evidence: [T03-S007])"
  "**Speak the EB's language** — frame in cost, time-to-value, and *sure-ness* (team confidence the initiative will work); EBs care about top/bottom-line impact and risk, not your product. (evidence: [T03-S007])"
  "**Tie the case to a decision + de-risk** — connect the business case to the decision criteria/process and address risk/cost-of-change to clear the path to approval. (evidence: [T03-S016, T03-S033])"
)
declare -a FAILURE_MODES=(
  "**Building the business case for the champion instead of the EB**: the champion can't approve budget; the case dies at their ceiling. Avoid: use the champion to *introduce* the EB; present value to the funder. (evidence: [T03-S007])"
  "**Feature-dumping to an outcome-focused EB**: EBs care about cost/time-to-value/risk, not your feature list. Avoid: Before/After + PBOs + differentiation in *their* language. (evidence: [T03-S016, T03-S007])"
  "**Leaving risk unaddressed → FOMU freezes the EB**: even a strong ROI case stalls if the buyer fears messing up. Avoid: de-risk explicitly (references, phased rollout, guarantees). (evidence: [T03-S033])"
  "**\"value / synergy / trusted advisor\" buzzwords without quantification**: hollowed-out language signals a feature-seller in disguise. Avoid: every value claim carries a number the buyer agreed to. (evidence: [T03-S016])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "build-sell-a-business-case-to-th-walkthrough"
fi
